engineAPI.triggerRun:
// packages/core/src/engine.ts

import type { WorkflowDefinition, RunOptions, RunHandle } from './types';

// Primary surface-facing API — every surface (desktop, CLI, VS Code, web) uses this.
export interface WorkflowEngine {
  /**
   * Load and validate a workflow definition.
   * Throws WorkflowValidationError if the schema is invalid.
   */
  loadWorkflow(source: WorkflowDefinition | string): Promise<LoadedWorkflow>;

  /**
   * Trigger a workflow run. Returns immediately with a RunHandle;
   * all progress is delivered via the event stream on the handle.
   */
  run(workflow: LoadedWorkflow, inputs: Record<string, unknown>, options?: RunOptions): RunHandle;

  /**
   * Resume a paused run (e.g. after human-gate approval).
   */
  resume(runId: string, gateId: string, decision: GateDecision): Promise<void>;

  /**
   * Cancel a running workflow. In-flight agent calls are interrupted.
   */
  cancel(runId: string): Promise<void>;

  /**
   * Retrieve a past run by ID (local store or cloud depending on mode).
   */
  getRunState(runId: string): Promise<RunState>;

  /**
   * List runs, optionally filtered.
   */
  listRuns(filter?: RunFilter): Promise<RunSummary[]>;
}

// Factory — surfaces call this once at startup.
export function createEngine(config: EngineConfig): WorkflowEngine;

export interface EngineConfig {
  executionMode: 'local' | 'cloud';
  apiKeys?: Record<string, string>;     // provider -> key (local mode)
  cloudEndpoint?: string;               // required in cloud mode
  cloudAuthToken?: string;              // from web portal auth bridge
  storageDir?: string;                  // local: where run state is persisted
  plugins?: PluginRegistration[];       // surface-supplied plugins
  mcpServers?: McpServerConfig[];       // globally available MCP servers
  telemetry?: TelemetryConfig;          // usage reporting to web portal
}

export interface RunOptions {
  dryRun?: boolean;                     // validate + resolve without executing
  stepMode?: boolean;                   // pause before each node (debug)
  tags?: string[];                      // for filtering in portal
  runId?: string;                       // supply to resume deterministically
  timeoutMs?: number;
}

// RunHandle is the live object returned by engine.run().
export interface RunHandle {
  readonly runId: string;
  readonly events: AsyncIterable<RunEvent>;   // primary streaming interface
  readonly state: () => RunState;             // synchronous snapshot
  cancel: () => Promise<void>;
  waitForCompletion: () => Promise<RunResult>;
}

engineAPI.streamingEvents:
// packages/core/src/events.ts

export type RunEvent =
  | RunStartedEvent
  | NodeStartedEvent
  | AgentTokenEvent
  | AgentToolCallEvent
  | AgentToolResultEvent
  | NodeCompletedEvent
  | NodeFailedEvent
  | HumanGatePausedEvent
  | HumanGateResumedEvent
  | RunCompletedEvent
  | RunFailedEvent
  | RunCancelledEvent;

// Every event carries a timestamp and runId.
interface BaseEvent {
  type: string;
  runId: string;
  timestamp: string;          // ISO 8601
  sequenceNumber: number;     // monotonically increasing per run
}

export interface RunStartedEvent extends BaseEvent {
  type: 'run:started';
  workflowId: string;
  inputs: Record<string, unknown>;
  executionMode: 'local' | 'cloud';
}

export interface NodeStartedEvent extends BaseEvent {
  type: 'node:started';
  nodeId: string;
  nodeType: string;
}

export interface AgentTokenEvent extends BaseEvent {
  type: 'agent:token';
  nodeId: string;
  token: string;              // streaming LLM token
  model: string;
}

export interface AgentToolCallEvent extends BaseEvent {
  type: 'agent:tool_call';
  nodeId: string;
  toolId: string;
  toolInput: unknown;         // sanitized — no secrets
}

export interface AgentToolResultEvent extends BaseEvent {
  type: 'agent:tool_result';
  nodeId: string;
  toolId: string;
  success: boolean;
  outputSummary: string;      // truncated for UI
}

export interface NodeCompletedEvent extends BaseEvent {
  type: 'node:completed';
  nodeId: string;
  output: unknown;
  tokensUsed: { input: number; output: number; model: string };
  durationMs: number;
}

export interface NodeFailedEvent extends BaseEvent {
  type: 'node:failed';
  nodeId: string;
  error: { code: string; message: string; retryable: boolean };
}

export interface HumanGatePausedEvent extends BaseEvent {
  type: 'human_gate:paused';
  nodeId: string;
  gateType: 'approval' | 'input' | 'review';
  message: string;
  assignee?: string;
  timeoutMs?: number;
  expiresAt?: string;
}

export interface HumanGateResumedEvent extends BaseEvent {
  type: 'human_gate:resumed';
  nodeId: string;
  decision: 'approved' | 'rejected' | 'input_provided';
  decidedBy: string;
  payload?: unknown;          // when gate_type=input
}

export interface RunCompletedEvent extends BaseEvent {
  type: 'run:completed';
  outputs: Record<string, unknown>;
  totalTokensUsed: TokenUsageSummary;
  durationMs: number;
}

export interface RunFailedEvent extends BaseEvent {
  type: 'run:failed';
  error: { code: string; message: string; nodeId?: string };
  partialOutputs: Record<string, unknown>;
}

