engineAPI.humanGate:
// packages/core/src/human-gate.ts

/**
 * Human gates persist their paused state across process restarts.
 * Local mode: saved to storageDir/runs/{runId}/gates/{gateId}.json
 * Cloud mode: managed by cloud worker, client polls or uses SSE
 */

export interface GateDecision {
  decision: 'approved' | 'rejected' | 'input_provided';
  decidedBy: string;          // user id or 'timeout_escalation'
  payload?: unknown;          // for gate_type=input
  comment?: string;
}

// When a human_gate node is reached:
// 1. Engine serializes full run state to disk (local) or cloud store.
// 2. Engine emits HumanGatePausedEvent — all surfaces receive it.
// 3. Engine suspends — no more processing, process may exit.
// 4. Surface presents approval UI (desktop modal, CLI prompt, portal page,
//    VS Code notification, or external webhook notification).
// 5. User acts — surface calls engine.resume(runId, gateId, decision).
// 6. Engine reloads run state, emits HumanGateResumedEvent, continues.

// Notification delivery:
export interface GateNotificationConfig {
  channels: ('in_app' | 'email' | 'webhook' | 'slack')[]; // configured in portal
  webhookUrl?: string;
  slackWebhookUrl?: string;
}

// Timeout behavior is declared per-node:
// timeout_action: reject   → auto-reject on timeout
// timeout_action: approve  → auto-approve on timeout (dangerous, use sparingly)
// timeout_action: escalate → notify fallback assignees, extend timeout

// Surface-agnostic resume example (CLI):
// $ agentflow resume <run-id> --gate <gate-id> --approve
// $ agentflow resume <run-id> --gate <gate-id> --reject --comment 'Too risky'
// $ agentflow resume <run-id> --gate <gate-id> --input '{"api_key": "..."}'

engineAPI.pluginAPI:
// packages/core/src/plugins.ts

/**
 * Plugin = a named set of tool implementations that agents can use.
 * Surfaces register plugins at engine creation time.
 * Plugins can also be published as npm packages and declared in workflow YAML.
 */

export interface ToolPlugin {
  id: string;                           // unique, e.g. 'github', 'jira', 'slack'
  version: string;
  displayName: string;
  tools: ToolImplementation[];
  setup?: (config: Record<string, unknown>) => Promise<void>;
  teardown?: () => Promise<void>;
}

export interface ToolImplementation {
  id: string;                           // must match tool declaration in YAML
  description: string;
  inputSchema: JSONSchema;              // validated before calling execute()
  outputSchema?: JSONSchema;
  execute(
    input: unknown,
    context: ToolExecutionContext
  ): AsyncGenerator<ToolEvent, ToolResult, void>;
}

// Generators let tools emit progress events back to the engine event stream.
export type ToolEvent =
  | { type: 'progress'; message: string }
  | { type: 'artifact'; name: string; content: string; mimeType: string };

export interface ToolResult {
  success: boolean;
  output: unknown;
  error?: string;
}

export interface ToolExecutionContext {
  runId: string;
  nodeId: string;
  workflowId: string;
  env: Record<string, string>;          // env vars declared in workflow
  abortSignal: AbortSignal;
  logger: ToolLogger;
}

// Plugin registration — called during engine initialization.
export interface PluginRegistration {
  plugin: ToolPlugin;
  config?: Record<string, unknown>;    // passed to plugin.setup()
}

// Built-in tools (always registered, no plugin needed):
// read_file, write_file, bash, web_search, http_request,
// git_diff, git_log, grep, list_directory

// Publishing a plugin as an npm package:
// package.json: { "agentflow-plugin": true, "main": "dist/index.js" }
// Workflow YAML can then reference:
//   tools:
//     - id: my_tool
//       type: plugin
//       package: '@org/agentflow-plugin-github'
//       config: { token_env: GITHUB_TOKEN }
